external_knowledge:
- 'CAT8500' is a specific type of product;
- 'SEP FY2012' refers to a specific fiscal month;
- 'Warehouse A' is a specific storage location;
- 'Electronics' is a category of products, and being 'active' means this category is currently operational;
- The 'petals blossomed' metaphorically refers to the quantity of products booked;
- 'Ready to be picked' means the product has a shipping date that is either in the past or today.

sql:
SELECT DISTINCT business_unit_id
FROM bookings
WHERE booking_status = 'confirmed';

external_knowledge:
- 'product category' refers to 'product_family_name';
- 'financial period' refers to 'fiscal_quarter_name';
- 'total bookings' means the sum of 'booked_qty' for each combination of product family and fiscal quarter.

sql:
SELECT product_family_id
FROM bookings
WHERE booking_id = 1;

SELECT COUNT(*)
FROM bookings
WHERE fiscal_month_id = (SELECT MAX(fiscal_month_id) FROM bookings);
